Selectize.define("clear_selection",function(e){var t=this;e=$.extend({title:"Clear Selection"},e),t.setup=function(){var s=t.setup;return function(){s.apply(t,arguments);var l=$('<div class="selectize-dropdown-header"><span class="selectize-dropdown-header-title">'+e.title+'</span><span class="selectize-dropdown-header-close">&times;</span></div>');t.$dropdown.prepend(l),l.on("mousedown",function(e){e.preventDefault(),e.stopPropagation(),t.clear(),t.close(),t.blur()})}}()});
